 157 | // --- UTILITIES ---
 158 | function base64ToText(str: string) {
 159 |     try {
 160 |         const binString = atob(str.replace(/\s/g, ''));
 161 |         const bytes = Uint8Array.from(binString, (m) => m.codePointAt(0)!);
 162 |         return new TextDecoder().decode(bytes);
 163 |     } catch (e) { return ""; }
 164 | }
