 166 | function textToBase64(str: string) {
 167 |     const bytes = new TextEncoder().encode(str);
 168 |     const binString = Array.from(bytes, (byte) => String.fromCharCode(byte)).join("");
 169 |     return btoa(binString);
 170 | }
