 176 | function isRecordInScope(record: any, scopePath: string): boolean {
 177 |     if (!scopePath || scopePath === "/" || scopePath === "") return true;
 178 |     if (record.type === 'Checkpoint') return true; // Always show checkpoints
 179 |     // Allow if matches scope OR is an Edge Function operation
 180 |     if (record.ops && Array.isArray(record.ops)) {
 181 |         return record.ops.some((op: any) => 
 182 |             (op.file_path && op.file_path.startsWith(scopePath)) || 
 183 |             op.is_resolved_ef ||
 184 |             (op.file_path && op.file_path.includes("supabase/functions/"))
 185 |         );
 186 |     }
 187 |     if (record.data && record.data.results && Array.isArray(record.data.results)) {
 188 |         return record.data.results.some((res: any) => 
 189 |             (res.file && res.file.startsWith(scopePath)) ||
 190 |             (res.file && res.file.includes("supabase/functions/"))
 191 |         );
 192 |     }
 193 |     return true;
 194 | }
