 211 | async function githubFetch(repo: string, path: string, options: RequestInit = {}) {
 212 |   // Intelligent Repo Parsing: If 'owner/repo' is passed, use it directly. Otherwise prepend GITHUB_USER.
 213 |   const cleanRepo = repo.includes('/') ? repo : `${GITHUB_USER}/${repo}`;
 214 |   const url = `https://api.github.com/repos/${cleanRepo}${path}`;
 215 |   
 216 |   const res = await fetch(url, { ...options, headers: { ...getHeaders(), ...options.headers } });
 217 |   
 218 |   if (!res.ok) {
 219 |       const text = await res.text();
 220 |       // Pass through the actual GitHub error details for debugging
 221 |       throw new Error(`GitHub API Error ${res.status} on ${url}: ${text}`);
 222 |   }
 223 |   if (res.status === 204) return {}; 
 224 |   return res.json();
 225 | }
