 227 | async function getFileRaw(repo: string, filePath: string, ref: string) {
 228 |   try {
 229 |     const data = await githubFetch(repo, `/contents/${filePath}?ref=${ref}`);
 230 |     return { content: data.content, sha: data.sha }; 
 231 |   } catch (e: any) { 
 232 |     console.error(`[getFileRaw] Error on ${filePath}:`, e.message);
 233 |     return { content: "", sha: "" }; 
 234 |   }
