 237 | async function updateFile(repo: string, filePath: string, content: string, sha: string, branch: string, message: string) {
 238 |   const encoded = textToBase64(content);
 239 |   const payload: any = { message, content: encoded, branch };
 240 |   if(sha) payload.sha = sha;
 241 |   
 242 |   const res = await githubFetch(repo, `/contents/${filePath}`, {
 243 |     method: "PUT",
 244 |     body: JSON.stringify(payload),
 245 |   });
 246 |   return res.commit.sha;
 247 | }
