 277 | async function ensureBranchExists(repo: string) {
 278 |   // 1. Check if DEV_BRANCH already exists
 279 |   try { 
 280 |       await githubFetch(repo, `/branches/${DEV_BRANCH}`); 
 281 |       return; 
 282 |   } catch (e) { /* Branch doesn't exist, proceed to create it */ }
 283 | 
 284 |   let baseSha = "";
 285 |   
 286 |   // 2. Try to find existing 'main' or 'master'
 287 |   try {
 288 |       const main = await githubFetch(repo, `/git/ref/heads/${MAIN_BRANCH}`);
 289 |       baseSha = main.object.sha;
 290 |   } catch (e) {
 291 |       try {
 292 |           // Fallback: Check for 'master' just in case
 293 |           const master = await githubFetch(repo, `/git/ref/heads/master`);
 294 |           baseSha = master.object.sha;
 295 |       } catch (e2) {
 296 |           // 3. REPO IS EMPTY (No main, no master)
 297 |           // We must create the "Root Commit" by creating a README
 298 |           console.log("Repo appears empty. Initializing with README.md...");
 299 |           try {
 300 |               // Create README directly on MAIN to initialize the repo history
 301 |               await updateFile(repo, "README.md", "# Project Initialized by Conduit", "", MAIN_BRANCH, "Initial commit");
 302 |               
 303 |               // Now that the commit exists, get its SHA
 304 |               const newMain = await githubFetch(repo, `/git/ref/heads/${MAIN_BRANCH}`);
 305 |               baseSha = newMain.object.sha;
 306 |           } catch (e3: any) {
 307 |               console.error("Failed to auto-initialize repo:", e3);
 308 |               throw new Error("Repository is empty and auto-initialization failed. Please create a README.md manually on GitHub.");
 309 |           }
 310 |       }
 311 |   }
 312 | 
 313 |   // 4. Create the DEV_BRANCH
 314 |   if (baseSha) {
 315 |       try {
 316 |           await githubFetch(repo, `/git/refs`, { 
 317 |               method: "POST", 
 318 |               body: JSON.stringify({ ref: `refs/heads/${DEV_BRANCH}`, sha: baseSha }) 
 319 |           });
 320 |       } catch (e:any) {
 321 |           console.error("Error creating dev branch refs:", e);
 322 |       }
 323 |   }
 324 | }
