 328 | async function genericRequestAI(role: keyof AIConfig['roles'], messages: any[], config?: AIConfig, tools?: any[], responseFormat?: any): Promise<any> {
 329 |   const provider = resolveProvider(role, config);
 330 |   if (!provider) throw new Error(`No provider found for role: ${role}`);
 331 | 
 332 |   // --- DEBUG LOGGING ---
 333 |   // 1. Critical Console Log (Visible in Supabase Dashboard)
 334 |   console.log(`\n=== [AI PROMPT SENT] Role: ${role} | Provider: ${provider.name} ===`);
 335 |   console.log(JSON.stringify(messages, null, 2));
 336 |   if (tools) console.log("TOOLS:", JSON.stringify(tools, null, 2));
 337 |   console.log("=== [END PROMPT] ===\n");
 338 | 
 339 |   // 2. Persistent DB Log
 340 |   // We use a try-catch to ensure logging failure doesn't block the actual AI request
 341 |   try {
 342 |       await supabase.from('conduit_logs').insert({
 343 |           repo_name: 'DEBUG_TRACE', // Utility function doesn't know repo, using placeholder
 344 |           type: 'ai_prompt_dump',
 345 |           data: { 
 346 |               role, 
 347 |               provider: provider.name, 
 348 |               model: provider.model, 
 349 |               timestamp: new Date().toISOString(),
 350 |               messages_preview: messages 
 351 |           }
 352 |       });
 353 |   } catch (e) { console.error("Background log failed:", e); }
 354 |   
 355 |   // Advanced Rotation Logic: Fetch Least-Recently-Used key from 'api_keys' table
 356 |   const serviceMap: Record<string, string> = { 
 357 |       'Deepseek_API': 'deepseek', 
 358 |       'GEMINI_API_KEY': 'gemini', 
 359 |       'GROQ_API_KEY': 'groq' 
 360 |   };
 361 |   const serviceName = serviceMap[provider.apiKeyEnv];
 362 |   let apiKey = "";
 363 | 
 364 |   if (serviceName) {
 365 |       const { data: keyRow } = await supabase
 366 |           .from('api_keys')
 367 |           .select('id, api_key')
 368 |           .eq('service', serviceName)
 369 |           .eq('is_active', true)
 370 |           .or(`cooldown_until.is.null,cooldown_until.lt.${new Date().toISOString()}`)
 371 |           .order('last_used_at', { ascending: true, nullsFirst: true })
 372 |           .limit(1)
 373 |           .maybeSingle();
 374 | 
 375 |       if (keyRow) {
 376 |           apiKey = keyRow.api_key;
 377 |           // Mark as used immediately to move it to the end of the rotation queue
 378 |           await supabase.from('api_keys').update({ last_used_at: new Date().toISOString() }).eq('id', keyRow.id);
 379 |       }
 380 |   }
 381 | 
 382 |   // Fallback to Env Var if no key found in DB or service not mapped
 383 |   if (!apiKey) {
 384 |       apiKey = Deno.env.get(provider.apiKeyEnv) || "";
 385 |       if (!apiKey) {
 386 |           if (provider.apiKeyEnv && provider.apiKeyEnv.length > 10) apiKey = provider.apiKeyEnv;
 387 |           else throw new Error(`Missing API Key: No active keys for '${serviceName || provider.apiKeyEnv}' in DB or Env`);
 388 |       }
 389 |   }
 390 | 
 391 |   // ADAPTER: Google Native
 392 |   if (provider.type === 'google') {
 393 |     const promptText = messages.map(m => `[${m.role.toUpperCase()}]: ${m.content}`).join('\n');
 394 |     const url = `${provider.baseUrl}?key=${apiKey}`;
 395 |     
 396 |     const payload: any = { 
 397 |         contents: [{ parts: [{ text: promptText }] }]
 398 |     };
 399 | 
 400 |     // ADAPTER: Google Strict Function Calling
 401 |     if (tools && tools.length > 0 && messages[0].content.includes('STRICT')) {
 402 |         payload.tool_config = {
 403 |             function_calling_config: {
 404 |                 mode: "ANY",
 405 |                 allowed_function_names: [tools[0].function.name]
 406 |             }
 407 |         };
 408 |     }
 409 | 
 410 |     // MAP OPENAI TOOLS TO GOOGLE FUNCTION DECLARATIONS
 411 |     if (tools && tools.length > 0) {
 412 |         const mapType = (t: any) => {
 413 |             // Flatten union types ["integer", "null"] -> "INTEGER"
 414 |             const rawType = Array.isArray(t) ? t[0] : t;
 415 |             if (rawType === "integer") return "INTEGER";
 416 |             if (rawType === "string") return "STRING";
 417 |             if (rawType === "boolean") return "BOOLEAN";
 418 |             if (rawType === "number") return "NUMBER";
 419 |             if (rawType === "object") return "OBJECT";
 420 |             if (rawType === "array") return "ARRAY";
 421 |             return "STRING"; // Fallback
 422 |         };
 423 | 
 424 |         const transformSchema = (schema: any): any => {
 425 |             const newSchema: any = { type: mapType(schema.type) };
 426 |             if (schema.properties) {
 427 |                 newSchema.properties = {};
 428 |                 for (const key in schema.properties) {
 429 |                     newSchema.properties[key] = transformSchema(schema.properties[key]);
 430 |                 }
 431 |             }
 432 |             if (schema.items) {
 433 |                 newSchema.items = transformSchema(schema.items);
 434 |             }
 435 |             if (schema.required) newSchema.required = schema.required;
 436 |             return newSchema;
 437 |         };
 438 | 
 439 |         payload.tools = [{
 440 |             function_declarations: tools.map((t: any) => ({
 441 |                 name: t.function.name,
 442 |                 description: t.function.description,
 443 |                 parameters: transformSchema(t.function.parameters)
 444 |             }))
 445 |         }];
 446 |     }
 447 |     
 448 |     const res = await fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
 449 |     const data = await res.json();
 450 |     
 451 |     if (data.error) throw new Error(`Google AI Error: ${data.error.message || JSON.stringify(data.error)}`);
 452 |     
 453 |     console.log(`\n=== [AI RESPONSE RECEIVED] Provider: ${provider.name} (Google) ===`);
 454 |     
 455 |     const parts = data.candidates?.[0]?.content?.parts || [];
 456 |     let combinedContent = "";
 457 |     let tool_calls: any[] = [];
 458 | 
 459 |     // Loop through all parts to catch both text and function calls
 460 |     for (const p of parts) {
 461 |         if (p.text) combinedContent += p.text;
 462 |         if (p.functionCall) {
 463 |             tool_calls.push({
 464 |                 function: {
 465 |                     name: p.functionCall.name,
 466 |                     arguments: JSON.stringify(p.functionCall.args)
 467 |                 }
 468 |             });
 469 |         }
 470 |     }
 471 | 
 472 |     return { 
 473 |       raw: data, 
 474 |       content: combinedContent,
 475 |       tool_calls: tool_calls.length > 0 ? tool_calls : undefined
 476 |     };
 477 |   }
 478 | 
 479 |   // ADAPTER: OpenAI Compatible (Standard)
 480 |   const body: any = {
 481 |     model: provider.model,
 482 |     messages: messages,
