 888 | // Helper: Finds code block ignoring whitespace, tabs, newlines, and quote styles
 889 | function findBlockRobust(originalContent: string, searchBlock: string): { start: number; end: number } | null {
 890 |   if (!searchBlock || !originalContent) return null;
 891 | 
 892 |   const createFingerprint = (str: string) => {
 893 |     let clean = "";
 894 |     const map: number[] = [];
 895 |     for (let i = 0; i < str.length; i++) {
 896 |       if (!/\s/.test(str[i])) {
 897 |         clean += str[i];
 898 |         map.push(i);
 899 |       }
 900 |     }
 901 |     return { clean, map };
 902 |   };
 903 | 
 904 |   const fileFP = createFingerprint(originalContent);
 905 |   const searchFP = createFingerprint(searchBlock);
 906 | 
 907 |   // 1. Strict Structural Match
 908 |   let matchIndex = fileFP.clean.indexOf(searchFP.clean);
 909 | 
 910 |   // 2. Quote-Agnostic Fallback (e.g. " vs ')
 911 |   if (matchIndex === -1) {
 912 |     const normalizeQuotes = (s: string) => s.replace(/['"`]/g, '"');
 913 |     matchIndex = normalizeQuotes(fileFP.clean).indexOf(normalizeQuotes(searchFP.clean));
 914 |   }
 915 | 
 916 |   if (matchIndex === -1) return null;
 917 | 
 918 |   const start = fileFP.map[matchIndex];
 919 |   const end = fileFP.map[matchIndex + searchFP.clean.length - 1] + 1;
 920 |   return { start, end };
 921 | }
