 923 | function applyOperation(content: string, op: any) {
 924 |   const lines = content.split("\n");
 925 |   
 926 |   // Helper to find line by trimmed content
 927 |   const getLineIndex = (anchor: string) => {
 928 |       const cleanAnchor = anchor.trim();
 929 |       return lines.findIndex(l => l.trim() === cleanAnchor);
 930 |   };
 931 | 
 932 |   try {
 933 |     // --- AI HEALING ---
 934 |     if (op.is_ai_fix) {
 935 |         if (op.ai_strategy === "range_replace" && op.start_line && op.end_line) {
 936 |             lines.splice(op.start_line - 1, (op.end_line - op.start_line) + 1, op.replace_with || op.content || "");
 937 |                         const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 938 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `✨ AI: ${shortMsg}` };
 939 |         }
 940 | 
 941 |         if (op.ai_strategy === "line_insert" && op.anchor_line) {
 942 |             const idx = op.anchor_line - 1;
 943 |             const payload = op.replace_with || op.content || "";
 944 |             if (op.action === "insert_after") {
 945 |                 lines.splice(idx + 1, 0, payload);
 946 |             } else if (op.action === "insert_before") {
 947 |                 lines.splice(idx, 0, payload);
 948 |             } else {
 949 |                 lines[idx] = payload;
 950 |             }
 951 |             const shortMsg = op.explanation ? (op.explanation.substring(0, 150) + "...") : "AI Fixed";
 952 |             return { newContent: lines.join("\n"), success: true, score: 95, message: `✨ AI: ${shortMsg}` };
 953 |         }
 954 |     }
 955 | 
 956 |     switch (op.action) {
 957 |       case "replace_block": {
 958 |         if (!op.find_block) return { newContent: content, success: false, score: 0, message: "Missing find_block" };
 959 |         
 960 |         // Strategy A: Exact Match
 961 |         if (content.includes(op.find_block)) {
 962 |             return { newContent: content.replace(op.find_block, op.replace_with || ""), success: true, score: 100, message: "Exact match" };
 963 |         }
 964 |         // Strategy B: Robust Match (Ignores whitespace/indentation)
 965 |         const match = findBlockRobust(content, op.find_block);
 966 |         if (match) {
 967 |             const before = content.substring(0, match.start);
 968 |             const after = content.substring(match.end);
 969 |             return { newContent: before + (op.replace_with || "") + after, success: true, score: 95, message: "Structure match" };
 970 |         }
 971 |         return { newContent: content, success: false, score: 0, message: "Block not found" };
 972 |       }
